package com.example.demo.controller;import com.example.demo.dto.ConfiguracionComercioDTO;import com.example.demo.services.ConfiguracionComercioService;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/configuracion")public class ConfiguracionComercioController{private final ConfiguracionComercioService service;public ConfiguracionComercioController(ConfiguracionComercioService service){this.service=service;}@GetMapping public ConfiguracionComercioDTO obtener(){return service.obtener();}@PutMapping public ConfiguracionComercioDTO guardar(@RequestBody ConfiguracionComercioDTO dto){return service.guardar(dto);}}
